v`.`master_id` AS `master_id`,`gcl`.`provider_event_id` AS `gcal_event_id`,`mcl`.`provider_event_id` AS `msft_event_id`,`acl`.`provider_event_id` AS `apple_event_id` from (((`tasks_v` `v` left join (select `cal_sync_ledger`.`task_id` AS `task_id`,any_value(`cal_sync_ledger`.`provider_event_id`) AS `provider_event_id` from `cal_sync_ledger` where ((`cal_sync_ledger`.`status` = 'active') and (`cal_sync_ledger`.`provider` = 'gcal') and (`cal_sync_ledger`.`task_id` is not null)) group by `cal_sync_ledger`.`task_id`) `gcl` on((`gcl`.`task_id` = `v`.`id`))) left join (select `cal_sync_ledger`.`task_id` AS `task_id`,any_value(`cal_sync_ledger`.`provider_event_id`) AS `provider_event_id` from `cal_sync_ledger` where ((`cal_sync_ledger`.`status` = 'active') and (`cal_sync_ledger`.`provider` = 'msft') and (`cal_sync_ledger`.`task_id` is not null)) group by `cal_sync_ledger`.`task_id`) `mcl` on((`mcl`.`task_id` = `v`.`id`))) left join (select `cal_sync_ledger`.`task_id` AS `task_id`,any_value(`cal_sync_ledger`.`provider_event_id`) AS `provider_event_id` from `cal_sync_ledger` where ((`cal_sync_ledger`.`status` = 'active') and (`cal_sync_ledger`.`provider` = 'apple') and (`cal_sync_ledger`.`task_id` is not null)) group by `cal_sync_ledger`.`task_id`) `acl` on((`acl`.`task_id` = `v`.`id`)));
